INSERT INTO `vacancies` (`id`, `company_id`, `reference_number`, `title`, `designation`, `description`, `requirements`, `required_skills`, `location`, `employment_type`, `min_experience`, `min_relevant_experience`, `publish_date`, `expire_date`, `is_active`, `approval_status`, `rejection_reason`, `sub1_approved_by`, `sub1_approved_at`, `global_approved_by`, `global_approved_at`, `rejected_by`, `rejected_at`, `status`, `created_by`, `created_at`, `updated_at`, `hired_application_id`) VALUES ('42', '3', 'GSH/2026/25/003', 'Internship - Software Developer (.Net)', 'Internship - Software Developer (.Net)', '• Male / Female Candidate\n• Age below 27 years.\n• Currently pursuing a Degree in Computer Science, Software Engineering, Information Technology, or a related field; recent graduates may also apply.\n• NIBM Diploma holders are encouraged to apply.\n• Basic knowledge of C# and the .NET Framework / .NET Core.\n• Familiarity with Java programming concepts.\n• Understanding of ASP.NET MVC or ASP.NET Core web application development.\n• Basic knowledge of HTML, CSS, and JavaScript.\n• Exposure to Angular or React will be considered an added advantage.\n• Understanding of Object-Oriented Programming (OOP) principles.\n• Familiarity with Git and version control practices.\n• Strong analytical and problem-solving skills.\n• Excellent communication skills and the ability to work effectively within a team environment.\n• A willingness to learn new technologies and adapt to evolving project requirements.', '• Assist in the design, development, testing, and maintenance of web applications using C#, Java, and ASP.NET Core.\n• Develop and consume RESTful APIs and integrate third-party services.\n• Write clean, scalable, and maintainable code following software development best practices and SOLID principles.\n• Participate in code reviews to ensure quality standards and continuous learning.\n• Work with SQL Server and Oracle databases to write optimized queries and manage database structures.\n• Support database operations using Entity Framework Core.\n• Collaborate with senior developers, product managers, and designers to transform business requirements into technical solutions.\n• Assist in debugging, troubleshooting, and resolving application issues.\n• Contribute to software documentation and technical discussions within the development team.\n', '.Net', 'colombo 2', 'Full-Time', '1-2 years', '1-2 years', '2026-06-18', '2026-07-11', '1', 'approved', NULL, '4', '2026-06-18 16:09:33', '994', '2026-06-18 16:10:25', NULL, NULL, 'approved', '5', '2026-06-18 15:57:59', '2026-06-18 16:10:25', NULL);
INSERT INTO `vacancies` (`id`, `company_id`, `reference_number`, `title`, `designation`, `description`, `requirements`, `required_skills`, `location`, `employment_type`, `min_experience`, `min_relevant_experience`, `publish_date`, `expire_date`, `is_active`, `approval_status`, `rejection_reason`, `sub1_approved_by`, `sub1_approved_at`, `global_approved_by`, `global_approved_at`, `rejected_by`, `rejected_at`, `status`, `created_by`, `created_at`, `updated_at`, `hired_application_id`) VALUES ('55', '2', 'ST/2026/26/001', 'Senior Executive – Human Resources (Payroll & Talent Development)', 'Senior Executive – Human Resources (Payroll & Talent Development)', '• Manage end-to-end non-executive payroll processes, ensuring accurate and timely payroll administration.\n• Handle employee resignations, terminations, attendance administration, overtime tracking, shift changes,and payroll-related system updates.\n• Maintain and update employee records, HRIS data, and organizational structure information.\n• Coordinate employee training programs, assessments, and talent development initiatives.\n• Support performance management activities, including annual appraisals, promotions, and internal\ninterviews.\n• Collaborate with department heads\nto identify employee development opportunities and succession planning\nrequirements.\n• Prepare and issue\nemployee-related documentation, including service letters, salary\nconfirmation letters, bank letters, and other HR correspondence.\n• Process EPF/ETF claims and ensure\ncompliance with company policies and statutory requirements.\n• Organize employee engagement\nactivities and company events in line with the annual event calendar.\n• Provide administrative support\nfor HR operations and perform any other duties assigned by management.', '• Bachelor\'s Degree in Human Resources Management, Business Management, or a related discipline.\n• Minimum 2–3 years of experience in Human Resources, preferably in payroll administration and talent\ndevelopment.\n• Strong knowledge of payrollprocessing, attendance management, labor regulations, and HR operations.\n• Experience working with HRIS and payroll systems is an added advantage.\n• Proficiency in Microsoft Office applications, particularly MS Excel.\n• Excellent organizational, communication, and interpersonal skills.\n• Strong analytical and problem-solving abilities with keen attention to detail.\n• Ability to handle confidential information with professionalism and integrity.\n• Capable of managing multiple priorities and meeting deadlines in a fast-paced environment.\n• Experience in employee training, performance management, and HR administration will be an added advantage.', 'Bachelor\'s Degree in Human Resources Management', 'boardroom', 'Full-Time', '1-2 years', '1-2 years', '2026-06-22', '2026-07-03', '1', 'approved', NULL, NULL, NULL, '994', '2026-06-22 11:01:56', NULL, NULL, 'approved', NULL, '2026-06-22 10:15:24', '2026-06-22 11:01:56', NULL);
INSERT INTO `vacancies` (`id`, `company_id`, `reference_number`, `title`, `designation`, `description`, `requirements`, `required_skills`, `location`, `employment_type`, `min_experience`, `min_relevant_experience`, `publish_date`, `expire_date`, `is_active`, `approval_status`, `rejection_reason`, `sub1_approved_by`, `sub1_approved_at`, `global_approved_by`, `global_approved_at`, `rejected_by`, `rejected_at`, `status`, `created_by`, `created_at`, `updated_at`, `hired_application_id`) VALUES ('57', '3', 'GSH/2026/26/002', 'JavaScript Backend Developer (AI-Driven)', 'JavaScript Backend Developer (AI-Driven)', '2+ years of backend development experience.\nStrong JavaScript and Node.js skills.\nGood understanding of REST APIs and backend architecture.\nExperience with PostgreSQL, MySQL, MongoDB, or Redis.\nStrong debugging and troubleshooting abilities.\nFamiliarity with Git and AWS is a plus.\nUnderstanding of software engineering fundamentals, design patterns, and clean code principles.\nAbility to work independently and communicate effectively in English.', '2+ years of backend development experience.\nStrong JavaScript and Node.js skills.\nGood understanding of REST APIs and backend architecture.\nExperience with PostgreSQL, MySQL, MongoDB, or Redis.\nStrong debugging and troubleshooting abilities.\nFamiliarity with Git and AWS is a plus.\nUnderstanding of software engineering fundamentals, design patterns, and clean code principles.\nAbility to work independently and communicate effectively in English.', 'Experience with AI-powered applications,LLMs,or AI agents.,Knowledge of OpenAI,Claude,Gemini', 'Colombo 03', 'Full-Time', '1-2 years', '1-2 years', '2026-06-22', '2026-07-11', '1', 'approved', NULL, '4', '2026-06-22 15:17:27', '994', '2026-06-22 15:17:37', NULL, NULL, 'approved', '5', '2026-06-22 13:55:38', '2026-06-22 15:17:37', NULL);
INSERT INTO `vacancies` (`id`, `company_id`, `reference_number`, `title`, `designation`, `description`, `requirements`, `required_skills`, `location`, `employment_type`, `min_experience`, `min_relevant_experience`, `publish_date`, `expire_date`, `is_active`, `approval_status`, `rejection_reason`, `sub1_approved_by`, `sub1_approved_at`, `global_approved_by`, `global_approved_at`, `rejected_by`, `rejected_at`, `status`, `created_by`, `created_at`, `updated_at`, `hired_application_id`) VALUES ('59', '3', 'GSH/2026/26/003', 'ASSISTANT ACCOUNTANT', 'ASSISTANT ACCOUNTANT', 'YOUR  ROLE:\n\n•Preparing monthly, quarterly and annual financial statements for given entities at group level.\n•Reviewing financial statements for given entities at Group level.\n•Performing month-end General Ledger closing function.\n•Reconciling monthly intercompany balances and preparing periodic consolidated financial statements.\n•Prepare cash flow reports and annual budgets and forecasts.\n•Preparing management reports and month-end reports as requested by the management.\n•Preparing periodic tax computations and responsible for all RAMIS reporting requirements.\n•Laise with tax authorities/ consultants and coordinate all tax matters.\n•Laise with auditors/banks and other third parties.\n•Facilitate the team and ensure that they are in line with company policies and deadlines.', 'YOUR  PROFILE:\n\n•A Bachelor’s degree in Finance or Accounting from a recognized University or Institute.\n•Qualified in ICASL/CIMA/ACCA.\n•Minimum 07 years of overall experience and 03 years of experience in a similar role.\n•Sound knowledge of taxation, IRD related compliances and accounting standards.\n•Excellent leadership skills with a passion to deliver results.\n•Self motivated individual a team player to lead cross functional teams.\n•High standard of technical, analytical & reporting skills.\n•Fluency in written & spoken English.\n•Conversant with MS Office packages and proficiency in Advanced Excel.\n ', 'Qualified in ICASL/CIMA/ACCA', 'No. 7E, Postmasters Place, Off Templers Road, Mount Lavinia, Sri Lanka', 'Full-Time', '5-7 years', '3-4 years', '2026-06-23', '2026-07-17', '1', 'approved', NULL, '4', '2026-06-23 13:32:04', '994', '2026-06-23 13:32:29', NULL, NULL, 'approved', '5', '2026-06-23 13:26:36', '2026-06-23 13:32:29', NULL);
INSERT INTO `vacancies` (`id`, `company_id`, `reference_number`, `title`, `designation`, `description`, `requirements`, `required_skills`, `location`, `employment_type`, `min_experience`, `min_relevant_experience`, `publish_date`, `expire_date`, `is_active`, `approval_status`, `rejection_reason`, `sub1_approved_by`, `sub1_approved_at`, `global_approved_by`, `global_approved_at`, `rejected_by`, `rejected_at`, `status`, `created_by`, `created_at`, `updated_at`, `hired_application_id`) VALUES ('60', '3', 'GSH/2026/26/004', 'SENIOR ACCOUNTS EXECUTIVE', 'SENIOR ACCOUNTS EXECUTIVE', 'YOUR ROLE:\n\n•Prepare annual budgets and re-forecast periodically to align with business priorities.\n•Finalization of segmental monthly management accounts.\n•Ensure compliance with statutory regulations\n•Liaise with internal and external stakeholders to ensure project alignment.\n•Perform computations and submit statutory returns through IRD portal in compliance with deadlines.\n•Perform periodic reconciliations with other group companies.', 'YOUR PROFILE:\n\n•Bachelor’s Degree in Finance or Accounting from a recognized university or institute and/or partly   qualified in CA or CIMA.\n•Minimum of 04 years’ experience in a similar role.\n•Prior experience in auditing will be considered a distinct advantage.\n•Expertise in taxation, statutory compliance, and financial reporting, complemented by proficiency in   QuickBooks.\n•Ability to work independently and exercise initiative with minimal supervision.', 'qualified in CA or CIMA', 'No. 7E, Postmasters Place, Off Templers Road, Mount Lavinia, Sri Lanka', 'Full-Time', '3-4 years', '3-4 years', '2026-06-23', '2026-06-27', '1', 'approved', NULL, '4', '2026-06-23 14:55:44', '994', '2026-06-23 14:56:36', NULL, NULL, 'approved', '5', '2026-06-23 14:54:29', '2026-06-23 14:56:36', NULL);
INSERT INTO `vacancies` (`id`, `company_id`, `reference_number`, `title`, `designation`, `description`, `requirements`, `required_skills`, `location`, `employment_type`, `min_experience`, `min_relevant_experience`, `publish_date`, `expire_date`, `is_active`, `approval_status`, `rejection_reason`, `sub1_approved_by`, `sub1_approved_at`, `global_approved_by`, `global_approved_at`, `rejected_by`, `rejected_at`, `status`, `created_by`, `created_at`, `updated_at`, `hired_application_id`) VALUES ('68', '1014', 'GSO/2026/27/001', 'Assistant Manager - IT', 'Assistant Manager - IT', '• Lead SAP ERP system support, implementation, and workflow automation across sector companies.\n• Oversee IT infrastructure including servers, networks, CCTV systems, and connectivity across multiple locations.\n• Manage Microsoft 365 (O365), SharePoint, email systems, and user access administration.\n• Ensure data backup, recovery, and IT security compliance across all systems.\n• Handle vendor management and procurement of IT products and services.\n• Develop and implement IT governance, policies, SOPs, and documentation.\n• Monitor voice, data, and internet services for uninterrupted operations.\n• Conduct IT awareness sessions and support end-user training.\n• Support digital transformation and continuous IT process improvements.', '• Bachelor\'s Degree in IT, Computer Science, or related field.\n• Strong knowledge of Microsoft 365, SharePoint, and networking. Knowledge of SAP can be considered an added advantage.\n• Minimum 4 years proven working experience.\n• Experience in CCTV, connectivity, and IT security practices.\n• Good understanding of IT governance and vendor management.\n• Certifications like ITIL / Microsoft / Cisco will be an added advantage.\n• Excellent communication and interpersonal skills to foster relationships with clients and partners.\n• Commitment and desire to achieve personal and company goals.\n• High interpersonal and analytical skills.\n\n\n', 'Degree in IT,Computer Science,or related field', 'No. 439, Galle Road, Colombo 03, Sri Lanka.', 'Full-Time', '1-2 years', '1-2 years', '2026-06-30', '2026-07-10', '1', 'approved', NULL, '1000', '2026-06-30 10:05:34', '994', '2026-06-30 10:07:19', NULL, NULL, 'approved', '1001', '2026-06-30 10:04:15', '2026-06-30 10:07:19', NULL);
