 Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Drew up interview score cards for hiring managers to use in interviews.\"},{\"skill\":\"Reference checks\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Completed reference checks for 30+ candidates.\"},{\"skill\":\"Employment contracts\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Made up contracts varying from part-time to full-time agreements.\"},{\"skill\":\"Employee relations matters\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Coached managers through employee relations matters including discipline and PIPs.\"},{\"skill\":\"Performance improvement plans\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Coached managers through employee relations matters including performance improvement plans.\"},{\"skill\":\"Coaching\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Launched a coaching and mentoring programme for graduates annually.\"},{\"skill\":\"Mentoring\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_con