ence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Maintained employee records and HRIS databases, ensuring data accuracy.\"},{\"skill\":\"Talent Development\",\"category\":\"Relevant Skills\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Monitored employee development plans and supported talent development initiatives.\"},{\"skill\":\"Training Coordination\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Coordinated training programs and assisted in HR reporting.\"},{\"skill\":\"Performance Management\",\"category\":\"Relevant Skills\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Supported annual performance reviews, promotions, and internal interviews.\"},{\"skill\":\"EPF/ETF Processing\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Processed EPF/ETF documentation and ensured compliance with labor regulations.\"},{\"skill\":\"HR Compliance\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Ensured compliance with labor regulations and statutory requirements.\"},{\"skill\":\"MS Excel\",\"category\":\"Relevant Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"3+ Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",