nd\":[\"Basic Networking\",\"Web Development Fundamentals\"],\"experience_summary\":\"The candidate has less than 1 year of overall and relevant experience, primarily gained through an IT Support Intern role and freelance web development projects. Their experience includes first-level technical support, web page development with React and basic web technologies, and database interaction with MySQL.\",\"fully_demonstrated_skills\":[],\"partially_demonstrated_skills\":[],\"qualifications_found\":[\"BSc (Hons) in Information Technology\",\"G.C.E. Advanced Level - Technology Stream\"],\"recruiter_insights\":[\"Overall Match Summary: Moderate Match. The candidate has a good foundation in IT support and basic web development, but lacks the extensive experience and specific system knowledge (SAP, Microsoft 365/SharePoint) required for an Assistant Manager role.\",\"Key Strengths: Proven experience in IT support, troubleshooting, and basic web development using relevant technologies like React. Strong communication and problem-solving skills are also evident.\",\"Related Value: The candidate\'s IT background and troubleshooting skills are valuable. Their experience with email configuration and documentation is also relevant to supporting IT operations.\",\"Skill Gaps: Significant gaps exist in managing IT infrastructure (servers, networks, CCTV), SAP ERP, Microsoft 365/SharePoint administration, IT security compliance, vendor management, and IT governance. The required 4 years of experience is not met.\",\"Additional Skills Observation: The candidate possesses several web development specific skills (PHP, MySQL, HTML, CSS, JavaScript) which are outside the core requirements of this IT management role.\",\"Risk Notes: The candidate\'s experience level is significantly lower than the minimum requirement. Core competencies such as SAP, O365, SharePoint, and infrastructure management are not demonstrated. Skills like REST API, Git, and GitHub are only mentioned without strong usage context.\",\"Recruiter Recommendation: Moderate Match. While the candidate shows potential in foundational IT support and development, they are not a strong fit for an Assistant Manager role requiring significant experience in enterprise systems and infrastructure management.\"],\"requirements_without_evidence\":[],\"salary_expectation\":\"Not specified\"}', NULL, 'On-site', '2026-07-17', '22:01', 'George Steuart Optimize — BoardRoom', 'No. 439, Galle Road, Colombo 03, Sri Lanka.', '2026-07-01 09:34:29', '0', '0', NULL, 'yes');
INSERT INTO `applications` (`id`, `vacancy_id`, `first_name`, `last_name`, `email`, `contact_number`, `overall_experience`, `relevant_experience`, `qualification`, `salary_expectation`, `cv_path`, `status`, `tags`, `skills_metadata`, `rejection_reason`, `interview_type`, `interview_date`, `interview_time`, `interview_location`, `interview_location_link`, `applied_at`, `future_consent`, `is_blocked`, `block_reason`, `interview_confirmed`) VALUES ('31', '69', 'Kavindu', 'Jayasinghe', 'georgesteuartit@gmail.com', '+94 77 123 4567', '1-2 years', '1-2 years', 'Bachelors Degree', '80000', 'cv_69_1782968899_6a45f2437c281.pdf', 'shortlisted', 'Helpdesk, Desktop Support, Remote Support, Ticket Handling, User Training, Microsoft 365, Outlook, Teams, SharePoint, Windows 10/11, Active Directory, User Account Support, LAN Troubleshooting, Wi-Fi Troubleshooting, TCP/IP, DNS, DHCP, Laptop Setup, Print', '{\"first_name\":\"Kavindu\",\"last_name\":\"Jayasinghe\",\"email\":\"georgesteuartit@gmail.com\",\"contact_number\":\"+94 77 123 4567\",\"qualification\":\"Bachelors Degree\",\"overall_experience\":\"1-2 years\",\"relevant_experience\":\"1-2 years\",\"skills_analysis\":[{\"skill\":\"User Training\",\"category\":\"Related Skills\",\"experience_level\":\"Basic\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Create simple user guides for common IT issues to reduce calls.\",\"verified\":true},{\"skill\":\"Prioritization\",\"category\":\"Related Skills\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Resolved desktop, laptop, and network connectivity issues within response times.\",\"verified\":true},{\"skill\":\"Attention to Detail\",\"category\":\"Related Skills\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Maintained accurate IT asset records for laptops, monitors, and printers.\",\"verified\":true},{\"skill\":\"IT Onboarding\",\"category\":\"Related Skills\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Project\",\"usage_context\":\"Created a standardized onboarding checklist for new joiners IT setup.\",\"verified\":true},{\"skill\":\"IT Documentation\",\"category\":\"Related Skills\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Project\",\"usage_context\":\"Prepared internal documentation for common IT troubleshooting steps.\",\"verified\":true},{\"skill\":\"Google IT Support Professional Certificate\",\"category\":\"Related Skills\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Certification\",\"usage_context\":\"Holds Google IT Support Professional Certificate for troubleshooting and support.\",\"verified\":true}],\"additional_skills\":[{\"skill\":\"Helpdesk\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Provide first-level IT support for business users, resolving issues.\",\"verified\":true},{\"skill\":\"Desktop Support\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Provide first-level IT support for business users, resolving issues.\",\"verified\":true},{\"skill\":\"Remote Support\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Provide first-level IT support for business users, resolving issues.\",\"verified\":true},{\"skill\":\"Ticket Handling\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Monitored helpdesk requests and updated ticket notes with issue details.\",\"verified\":true},{\"skill\":\"Microsoft 365\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Support Microsoft 365 users with Outlook, Teams, and SharePoint assistance.\",\"verified\":true},{\"skill\":\"Outlook\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Resolve Outlook issues for business users and assist with profile configuration.\",\"verified\":true},{\"skill\":\"Teams\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Resolve Teams access issues for business users.\",\"verified\":true},{\"skill\":\"SharePoint\",\"experience_level\":\"Basic\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Provide guidance on SharePoint file access for business users.\",\"verified\":true},{\"skill\":\"Windows 10/11\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Prepare laptops by applying Windows updates and troubleshooting issues.\",\"verified\":true},{\"skill\":\"Active Directory\",\"experience_level\":\"Basic\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Internship\",\"usage_context\":\"Supported basic Active Directory activities like user creation and account requests.\",\"verified\":true},{\"skill\":\"User Account Support\",\"experience_level\":\"Basic\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Internship\",\"usage_context\":\"Supported basic Active Directory activities and documentation for senior IT staff.\",\"verified\":true},{\"skill\":\"LAN Troubleshooting\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Troubleshoot LAN issues using TCP/IP, DNS, DHCP, and IP configuration checks.\",\"verified\":true},{\"skill\":\"Wi-Fi Troubleshooting\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Troubleshoot connectivity issues using TCP/IP, DNS, DHCP, and IP configuration checks.\",\"verified\":true},{\"skill\":\"TCP/IP\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Troubleshoot network connectivity issues using TCP/IP protocols.\",\"verified\":true},{\"skill\":\"DNS\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Troubleshoot network connectivity issues using DNS.\",\"verified\":true},{\"skill\":\"DHCP\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Troubleshoot network connectivity issues using DHCP.\",\"verified\":true},{\"skill\":\"Laptop Setup\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Prepare laptops for new joiners by installing software and configuring settings.\",\"verified\":true},{\"skill\":\"Printer Support\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Resolve printer issues and coordinate with vendors for repairs.\",\"verified\":true},{\"skill\":\"Scanner Support\",\"experience_level\":\"Basic\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Provided support for scanner issues as part of general hardware support.\",\"verified\":true},{\"skill\":\"ERP User Support\",\"experience_level\":\"Basic\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Internship\",\"usage_context\":\"Helped business users with ERP login and report access problems.\",\"verified\":true},{\"skill\":\"Data Backup Support\",\"experience_level\":\"Basic\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Weak Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Provided support for data backup processes.\",\"verified\":true},{\"skill\":\"Basic SQL\",\"experience_level\":\"Basic\",\"estimated_duration\":\"Less than 3 Months\",\"evidence_strength\":\"Weak Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Used basic SQL for reporting purposes.\",\"verified\":true},{\"skill\":\"Excel Reporting\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Maintained IT asset records using Excel-based registers.\",\"verified\":true},{\"skill\":\"Documentation\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Created user guides and internal documentation for IT troubleshooting.\",\"verified\":true},{\"skill\":\"Communication\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Communicated with users and vendors, keeping users updated on progress.\",\"verified\":true},{\"skill\":\"Problem Solving\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Resolved desktop, laptop, and network connectivity issues for users.\",\"verified\":true},{\"skill\":\"Vendor Coordination\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Coordinated with vendors for printer faults, hardware repairs, and warranty replacements.\",\"verified\":true},{\"skill\":\"Windows OS Installation\",\"experience_level\":\"Advanced\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Internship\",\"usage_context\":\"Assisted the IT team with Windows OS installation and software troubleshooting.\",\"verified\":true},{\"skill\":\"Hardware Diagnostics\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Moderate Evidence\",\"evidence_source\":\"Internship\",\"usage_context\":\"Supported the IT team with hardware diagnostics and troubleshooting.\",\"verified\":true},{\"skill\":\"Network Troubleshooting\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Professional Experience\",\"usage_context\":\"Troubleshoot network connectivity issues using TCP/IP, DNS, DHCP.\",\"verified\":true},{\"skill\":\"Microsoft 365 Fundamentals\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Certification\",\"usage_context\":\"Completed Microsoft 365 Fundamentals (MS-900) learning path.\",\"verified\":true},{\"skill\":\"Networking Basics\",\"experience_level\":\"Intermediate\",\"estimated_duration\":\"1–2 Years\",\"evidence_strength\":\"Strong Evidence\",\"evidence_source\":\"Certification\",\"usage_context\":\"Completed Cisco Networking Basics, covering TCP/IP, LAN, Wi-Fi.\",\"verified\":true}],\"certifications_found\":[\"Microsoft 365 Fundamentals - MS-900 learning path completed\",\"Cisco Networking Basics - TCP/IP, LAN, Wi-Fi and troubleshooting fundamentals\",\"Google IT Support Professional Certificate - troubleshooting, customer support, operating systems, system administration\"],\"experience_summary\":\"IT Associate with over 2 years of experience in user support, desktop troubleshooting, Microsoft 365 administration support, hardware and printer support, and basic network troubleshooting.\",\"fully_demonstrated_skills\":[],\"partially_demonstrated_skills\":[\"User Training\",\"SharePoint\",\"Active Directory\",\"User Account Support\",\"Scanner Support\",\"ERP User Support\",\"Data Backup Support\",\"Excel Reporting\",\"Hardware Diagnostics\",\"IT Onboarding\"],\"qualifications_found\":[\"Bachelor of Science in Information Technology\",\"Diploma in Computer Hardware and Network Support\"],\"recruiter_insights\":[\"Overall Match Summary: The candidate possesses a solid foundation in IT support and troubleshooting, with relevant experience in core areas like Helpdesk, Microsoft 365, and network basics. However, the job description is extremely vague, making a precise match difficult. The candidate\'s skills are more aligned with a general IT support role.\",\"Key Strengths: Strong practical experience in Helpdesk, Desktop Support, Microsoft 365 administration support, and network troubleshooting (LAN/Wi-Fi, TCP/IP, DNS, DHCP). Proven ability in vendor coordination, user support documentation, and essential soft skills like communication and problem-solving.\",\"Related Value: Skills like ERP user support, Excel reporting, and hardware diagnostics, while not directly mandatory based on the JD, are valuable within an IT support context and demonstrate a broader understanding of business systems.\",\"Skill Gaps: The job description\'s vagueness (\'software engineering degree\' as a mandatory skill for an \'abc\' role) creates ambiguity. If \'software engineering degree\' is a strict requirement and the candidate\'s IT degree is not considered equivalent, this is a gap. Other mandatory skills are not detailed enough to assess.\",\"Additional Skills Observation: Basic SQL is listed but has weak evidence and is classified as an additional skill, indicating it\'s not a core strength for this role.\",\"Risk Notes: The primary risk is the extreme vagueness of the job description, particularly the \'software engineering degree\' mandatory skill. The candidate\'s IT degree may not meet this specific, if unusual, requirement for a role titled \'abc\'. Evidence for some skills like basic SQL is weak.\",\"Recruiter Recommendation: Moderate Match - The candidate has relevant IT support skills. However, the \'software engineering degree\' mandatory requirement is a significant concern given the candidate\'s IT degree. Further clarification on the role and the definition of \'software engineering degree\' is needed. If the role is indeed for software engineering, the candidate is Not Suitable. If \'software engineering degree\' was a typo and the role is IT Support, the candidate would be a Good Match.\"],\"requirements_without_evidence\":[],\"salary_expectation\":\"Not specified\"}', NULL, 'On-site', '2026-07-30', '16:25', 'George Steuart Optimize — BoardRoom', 'No. 439, Galle Road, Colombo 03, Sri Lanka.', '2026-07-02 10:38:19', '0', '0', NULL, 'yes');
