svfsef\r\n        </blockquote>\r\n        <p>You can login to the admin portal, make the necessary corrections, and resubmit it for approval.</p>\r\n            <div style=\'text-align: center; margin: 30px 0;\'>\r\n                <a href=\'http://localhost:3000/admin/vacancies?highlight=30\' style=\'padding: 12px 24px; background-color: #2a050b; color: #fff; text-decoration: none; border-radius: 5px; font-weight: bold;\'>Go to Vacancies</a>\r\n            </div>\r\n            <p style=\'font-size: 12px; color: #777;\'>This is an automated system notification. Please do not reply directly to this email.</p>\r\n        </div>\r\n    </div>\r\n    ', 'sent', '1', NULL, '2026-06-18 13:39:21', '2026-06-18 13:39:27');
