9;font-size:11px;font-weight:700;text-align:center;line-height:20px;\'>2</div>\r\n                </td>\r\n                <td valign=\'top\' style=\'padding-bottom:16px;\'>\r\n                  <p style=\'margin:0 0 4px;font-size:13px;font-weight:700;color:#1e293b;\'>Modify &amp; Refine Requisition</p>\r\n                  <p style=\'margin:0;font-size:12px;color:#64748b;line-height:1.4;\'>Edit the requisition details in the portal to fix the issues mentioned in the reviewer feedback.</p>\r\n                </td>\r\n              </tr>\r\n              <tr>\r\n                <td valign=\'top\' style=\'width:28px;\'>\r\n                  <div style=\'width:20px;height:20px;border-radius:50%;background:#e53e3e;color:#ffffff;font-size:11px;font-weight:700;text-align:center;line-height:20px;\'>3</div>\r\n                </td>\r\n                <td valign=\'top\'>\r\n                  <p style=\'margin:0 0 4px;font-size:13px;font-weight:700;color:#1e293b;\'>Submit for Re-approval</p>\r\n                  <p style=\'margin:0;font-size:12px;color:#64748b;line-height:1.4;\'>Save and resubmit the vacancy requisition to put it back in the approval pipeline.</p>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </div>\r\n\r\n          <!-- CTA Button -->\r\n          <div style=\'text-align:center;margin-bottom:12px;\'>\r\n            \r\n    <table cellpadding=\'0\' cellspacing=\'0\' style=\'margin:0 auto;\'>\r\n      <tr>\r\n        <td align=\'center\' style=\'border-radius:10px;background:#2a050b;\'>\r\n          <a href=\'http://localhost:3000/admin/vacancies?highlight=45\' target=\'_blank\'\r\n             style=\'display:inline-block;padding:14px 32px;font-size:14px;font-weight:700;color:#ffffff;text-decoration:none;border-radius:10px;letter-spacing:0.3px;\'>\r\n            &#9998;&nbsp; Edit &amp; Resubmit Requisition\r\n          </a>\r\n        </td>\r\n      </tr>\r\n    </table>\r\n    \r\n          </div>\r\n        \r\n      