!-- HEADER BANNER -->\r\n            <tr>\r\n              <td class=\'email-header\' style=\'background:linear-gradient(135deg,#1a0208 0%,#2a050b 55%,#3d0813 100%);border-radius:15px 15px 0 0;padding:28px 36px;\'>\r\n                <table width=\'100%\' cellpadding=\'0\' cellspacing=\'0\'>\r\n                  <tr>\r\n                    <td>\r\n                      <p style=\'margin:0;color:rgba(200,169,81,0.9);font-size:11px;font-weight:700;letter-spacing:2px;text-transform:uppercase;\'>George Steuart &amp; Company Ltd</p>\r\n                      <h1 class=\'mobile-title\' style=\'margin:4px 0 0;color:#ffffff;font-size:22px;font-weight:800;letter-spacing:-0.3px;\'>Careers Portal</h1>\r\n                    </td>\r\n                    <td align=\'right\'>\r\n                      <div style=\'width:48px;height:48px;background:rgba(200,169,81,0.15);border:2px solid rgba(200,169,81,0.4);border-radius:12px;display:inline-flex;align-items:center;justify-content:center;\'>\r\n                        <span style=\'color:#C8A951;font-size:22px;font-weight:900;\'>GS</span>\r\n                      </div>\r\n                    </td>\r\n                  </tr>\r\n                </table>\r\n              </td>\r\n            </tr>\r\n\r\n            <!-- CONTENT CARD -->\r\n            <tr>\r\n              <td class=\'email-body\' style=\'background:#ffffff;padding:36px;\'>\r\n                \r\n          <!-- Greeting -->\r\n          <p style=\'margin:0 0 6px;font-size:14px;color:#64748b;\'>Dear <strong style=\'color:#1e293b;\'>Admin</strong>,</p>\r\n\r\n          <!-- Status Pill + Heading -->\r\n          <div style=\'margin:16px 0 8px;\'>\r\n    <span style=\'display:inline-block;background-color:#fef3c7;color:#92400e;padding:5px 14px;border-radius:100px;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:1px;line-height:1.2;vertical-align:middle;\'>\r\n      <span style=\'width:6px;height:6px;border-radius:50%;background-color:#f59e0b;display:inline-block;vertical-align:middle;margin-right:6px;margin-top:-2px;\'></span>\r\n      <span style=\'vertical-align:middle;\'>Awaiting Global Approval</span>\r\n    </span>\r\n    </div>\r\n          <h2 style=\'margin:0 0 12px;font-size:20px;font-weight:800;color:#1a0208;line-height:1.3;\'>Resubmitted Requisition Approved by Sub Admin 1 — Your Action Required</h2>\r\n\r\n          <!-- Intro -->\r\n          <p style=\'margin:0 0 24px;font-size:14px;color:#334155;line-height:1.6;\'>A previously rejected job vacancy requisition has been edited, approved by Sub Admin 1, and is now awaiting your final approval as <strong>Global Admin</strong> to publish it on the careers portal.</p>\r\n\r\n          <!-- Vacancy Info Card -->\r\n          <div style=\'background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;padding:20px;margin-bottom:24px;\'>\r\n            <p style=\'margin:0 0 14px;font-size:11px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;\'>Requisition Details</p>\r\n            <table width=\'100%\' cellpadding=\'0\' cellspacing=\'0\'>\r\n              \r\n    <tr>\r\n      <td style=\'padding:12px 0;border-bottom:1px solid #f1f5f9;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Position / Title</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'>Senior Executive – Human Resources (Payroll &amp; Talent Development)</div>\r\n      </td>\r\n    </tr>\r\n    \r\n    <tr>\r\n      <td style=\'padding:12px 0;border-bottom:1px solid #f1f5f9;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Reference No.</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'><span style=\'font-family:monospace;font-size:13px;color:#C8A951;\'>ST/2026/26/001</span></div>\r\n      </td>\r\n    </tr>\r\n    \r\n    <tr>\r\n      <td style=\'padding:12px 0;border-bottom:1px solid #f1f5f9;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Company</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'>George Steuart Teas</div>\r\n      </td>\r\n    </tr>\r\n    \r\n            </table>\r\n          </div>\r\n\r\n          <!-- Note -->\r\n          <div style=\'background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:14px 18px;margin-bottom:28px;\'>\r\n            <p style=\'margin:0 0 4px;font-size:11px;font-weight:700;color:#c2410c;text-transform:uppercase;letter-spacing:0.5px;\'>&#9888;&nbsp; Action Required</p>\r\n            <p style=\'margin:0 0 8px;font-size:13px;color:#475569;\'>Please log in to the Careers Portal and review this requisition. You can approve it to make it live, or reject it with a reason.</p>\r\n          </div>\r\n\r\n          <!-- CTA Button -->\r\n          <div style=\'text-align:center;margin-bottom:8px;\'>\r\n            \r\n    <table cellpadding=\'0\' cellspacing=\'0\' style=\'margin:0 auto;width:100%;max-width:280px;\'>\r\n      <tr>\r\n        <td align=\'center\' style=\'border-radius:10px;background:#2a050b;\'>\r\n          <a href=\'http://localhost:3000/admin/approvals?highlight=55\' target=\'_blank\'\r\n             style=\'display:block;padding:14px 24px;font-size:14px;font-weight:700;color:#ffffff;text-decoration:none;border-radius:10px;letter-spacing:0.3px;text-align:center;\'>\r\n            &#9989;&nbsp; Review &amp; Give Final Approval\r\n          </a>\r\n        </td>\r\n      </tr>\r\n    </table>\r\n    \r\n          </div>\r\n        \r\n              </td>\r\n            </tr>\r\n\r\n            <!-- FOOTER -->\r\n            <tr>\r\n              <td class=\'email-footer\' style=\'background:#f8fafc;border-top:1px solid #e2e8f0;border-radius:0 0 15px 15px;padding:20px 36px;text-align:center;\'>\r\n                <p style=\'margin:0;font-size:11px;color:#94a3b8;line-height:1.6;\'>\r\n                  This is an automated notification from the George Steuart Careers Portal.<br>\r\n                  Please do not reply directly to this email.\r\n                </p>\r\n                <p style=\'margin:8px 0 0;font-size:10px;color:#cbd5e1;\'>\r\n                  &copy; 2026 George Steuart &amp; Company Ltd. All rights reserved.\r\n                </p>\r\n              </td>\r\n            </tr>\r\n\r\n          </table>\r\n        </td></tr>\r\n      </table>\r\n    </body>\r\n    </html>\r\n    ', 'sent', '1', NULL, '2026-06-22 11:01:10', '2026-06-22 11:01:30');
