e-block;vertical-align:middle;margin-right:6px;margin-top:-2px;\'></span>\r\n      <span style=\'vertical-align:middle;\'>Pending Your Approval</span>\r\n    </span>\r\n    </div>\r\n          <h2 style=\'margin:0 0 12px;font-size:20px;font-weight:800;color:#1a0208;line-height:1.3;\'>New Requisition Requires Your Review</h2>\r\n\r\n          <!-- Intro -->\r\n          <p style=\'margin:0 0 24px;font-size:14px;color:#334155;line-height:1.6;\'>A new job vacancy requisition has been submitted by your team and is <strong>awaiting your approval</strong> as Sub Admin 1 before it proceeds to the Global Admin.</p>\r\n\r\n          <!-- Vacancy Info Card -->\r\n          <div style=\'background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;padding:20px;margin-bottom:24px;\'>\r\n            <p style=\'margin:0 0 14px;font-size:11px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;\'>Requisition Details</p>\r\n            <table width=\'100%\' cellpadding=\'0\' cellspacing=\'0\'>\r\n              \r\n    <tr>\r\n      <td style=\'padding:12px 0;border-bottom:1px solid #f1f5f9;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Position / Title</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'>aaa</div>\r\n      </td>\r\n    </tr>\r\n    \r\n    <tr>\r\n      <td style=\'padding:12px 0;border-bottom:1px solid #f1f5f9;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Reference No.</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'><span style=\'font-family:monospace;font-size:13px;color:#C8A951;\'>GSH/2026/26/003</span></div>\r\n      </td>\r\n    </tr>\r\n    \r\n    <tr>\r\n      <td style=\'padding:12px 0;border-bottom:1px solid #f1f5f9;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Company</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'>George Steuart Health</div>\r\n      </td>\r\n    </tr>\r\n    \r\n            </table>\r\n          </div>\r\n\r\n          <!-- Note -->\r\n          <div style=\'background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:14px 18px;margin-bottom:28px;\'>\r\n            <p style=\'margin:0 0 4px;font-size:11px;font-weight:700;color:#c2410c;text-transform:uppercase;letter-spacing:0.5px;\'>&#9888;&nbsp; Action Required</p>\r\n            <p style=\'margin:0 0 8px;font-size:13px;color:#475569;\'>Please review the details carefully and either <strong>approve</strong> to forward it to the Global Admin, or <strong>reject</strong> with a reason.</p>\r\n          </div>\r\n\r\n          <!-- CTA Button -->\r\n          <div style=\'text-align:center;margin-bottom:8px;\'>\r\n            \r\n    <table cellpadding=\'0\' cellspacing=\'0\' style=\'margin:0 auto;width:100%;max-width:280px;\'>\r\n      <tr>\r\n        <td align=\'center\' style=\'border-radius:10px;background:#2a050b;\'>\r\n          <a href=\'http://localhost:3000/admin/approvals?highlight=58\' target=\'_blank\'\r\n             style=\'display:block;padding:14px 24px;font-size:14px;font-weight:700;color:#ffffff;text-decoration:none;border-radius:10px;letter-spacing:0.3px;text-align:center;\'>\r\n            &#128269;&nbsp; Review &amp; Approve Requisition\r\n          </a>\r\n        </td>\r\n      </tr>\r\n    </table>\r\n    \r\n          </div>\r\n        \r\n              </td>\r\n            </tr>\r\n\r\n            <!-- FOOTER -->\r\n            <tr>\r\n              <td class=\'email-footer\' style=\'background:#f8fafc;border-top:1px solid #e2e8f0;border-radius:0 0 15px 15px;padding:20px 36px;text-align:center;\'>\r\n                <p style=\'margin:0;font-size:11px;color:#94a3b8;line-height:1.6;\'>\r\n                  This is an automated notification from the George Steuart Careers Portal.<br>\r\n                  Please do not reply directly to this email.\r\n                </p>\r\n                <p style=\'margin:8px 0 0;font-size:10px;color:#cbd5e1;\'>\r\n                  &copy; 2026 George Steuart &amp; Company Ltd. All rights reserved.\r\n                </p>\r\n              </td>\r\n            </tr>\r\n\r\n          </table>\r\n        </td></tr>\r\n      </table>\r\n    </body>\r\n    </html>\r\n    ', 'sent', '1', NULL, '2026-06-22 15:30:12', '2026-06-22 15:30:31');
INSERT INTO `email_queue` (`id`, `recipient_email`, `recipient_name`, `subject`, `body`, `status`, `attempts`, `last_error`, `created_at`, `updated_at`) VALUES ('132', 'nadumi672@gmail.com', 'Nimal', 'Application Received - Senior Executive – Human Resources (Payroll & Talent Development) | George Steuart Group', '\r\n    <!DOCTYPE html>\r\n    <html>\r\n    <head>\r\n        <meta charset=\'UTF-8\'>\r\n        <meta name=\'viewport\' content=\'width=device-width, initial-scale=1.0\'>\r\n        <style>\r\n            body { font-family: \'Segoe UI\', Roboto, Helvetica, Arial, sans-serif; line-height: 1.6; color: #1e293b; margin: 0; padding: 0; background-color: #f8fafc; }\r\n            .wrapper { width: 100%; table-layout: fixed; background-color: #f8fafc; padding-bottom: 40px; }\r\n            .container { max-width: 600px; margin: 0 auto; background-color: #ffffff; border-radius: 16px; overflow: hidden; margin-top: 40px; box-shadow: 0 10px 25px rgba(0,0,0,0.05); }\r\n            .header { background-color: #1a1a2e; padding: 40px 20px; text-align: center; border-bottom: 5px solid #c8a951; }\r\n            .header img { height: 60px; margin-bottom: 15px; }\r\n            .header h1 { color: #ffffff; margin: 0; font-size: 22px; letter-spacing: 2px; text-transform: uppercase; font-weight: 700; }\r\n            .header p { color: #c8a951; margin: 5px 0 0; text-transform: uppercase; font-size: 11px; font-weight: 800; letter-spacing: 1.5px; }\r\n            .content { padding: 40px 35px; }\r\n            .greeting { font-size: 20px; color: #1a1a2e; margin-bottom: 24px; font-weight: 700; }\r\n            .success-badge { display: inline-block; background-color: #f0fdf4; color: #166534; padding: 6px 16px; border-radius: 20px; font-size: 13px; font-weight: 600; margin-bottom: 20px; border: 1px solid #dcfce7; }\r\n            .info-card { background-color: #fdfaf3; border-radius: 12px; padding: 25px; margin: 25px 0; border-left: 4px solid #c8a951; }\r\n            .info-row { margin-bottom: 12px; }\r\n            .info-row:last-child { margin-bottom: 0; }\r\n            .info-label { color: #64748b; font-size: 12px; text-transform: uppercase; font-weight: 700; letter-spacing: 0.5px; margin-bottom: 2px; }\r\n            .info-value { color: #1a1a2e; font-size: 15px; font-weight: 600; }\r\n            .next-steps { background-color: #f8fafc; border-radius: 12px; padding: 20px; margin-top: 30px; }\r\n            .next-steps h3 { margin-top: 0; font-size: 16px; color: #1a1a2e; }\r\n            .footer { padding: 30px; text-align: center; font-size: 12px; color: #94a3b8; background-color: #ffffff; }\r\n            .footer-divider { border: 0; border-top: 1px solid #f1f5f9; margin: 0 35px; }\r\n        </style>\r\n    </head>\r\n    <body>\r\n        <div class=\'wrapper\'>\r\n            <div class=\'container\'>\r\n                <div class=\'header\'>\r\n                    <h1>GEORGE STEUART</h1>\r\n                    <p>ESTABLISHED 1835</p>\r\n                </div>\r\n                <div class=\'content\'>\r\n                    <div class=\'greeting\'>Hello Nimal,</div>\r\n                    <div class=\'success-badge\'>✓ Application Received Successfully</div>\r\n                    <p>Thank you for your interest in joining <strong>George Steuart Group</strong>. We have successfully received your application and it is now being reviewed by our Talent Acquisition team.</p>\r\n                    \r\n                    <div class=\'info-card\'>\r\n                        <div class=\'info-row\'>\r\n                            <div class=\'info-label\'>Position</div>\r\n                            <div class=\'info-value\'>Senior Executive – Human Resources (Payroll & Talent Development)</div>\r\n                        </div>\r\n                        <div class=\'info-row\'>\r\n                            <div class=\'info-label\'>Job Reference No</div>\r\n                            <div class=\'info-value\'>ST/2026/26/001</div>\r\n                        </div>\r\n                        <div class=\'info-row\'>\r\n                            <div class=\'info-label\'>Entity</div>\r\n                            <div class=\'info-value\'>George Steuart Teas</div>\r\n                        </div>\r\n                    </div>\r\n \r\n                    <div class=\'next-steps\'>\r\n                        <h3>What\'s next?</h3>\r\n                        <p style=\'margin-bottom: 0; font-size: 14px;\'>Our team will evaluate your profile against the role requirements. If your experience aligns with our needs, we will reach out to you directly for the next steps in the selection process.</p>\r\n                    </div>\r\n                    \r\n                    <p style=\'margin-top: 30px;\'>Best regards,<br>\r\n                    <strong style=\'color: #1a1a2e;\'>Talent Acquisition Team</strong><br>\r\n                    George Steuart Group</p>\r\n                </div>\r\n                <hr class=\'footer-divider\'>\r\n                <div class=\'footer\'>\r\n                    &copy; 2026 George Steuart Group. All Rights Reserved.<br>\r\n                    No. 439, Galle Road, Colombo 03, Sri Lanka.<br>\r\n                    <p style=\'font-size: 10px; margin-top: 15px;\'>This is an automated system notification. Please do not reply to this email.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </body>\r\n    </html>', 'sent', '1', NULL, '2026-06-22 17:02:36', '2026-06-22 17:02:44');
INSERT INTO `email_queue` (`id`, `recipient_email`, `recipient_name`, `subject`, `body`, `status`, `attempts`, `last_error`, `created_at`, `updated_at`) VALUES ('133', 'nadumi672@gmail.com', 'Nimal', 'Interview Invitation - Senior Executive – Human Resources (Payroll & Talent Development) | George Steuart Group', '\r\n    <!DOCTYPE html>\r\n    <html>\r\n    <head>\r\n        <meta charset=\'UTF-8\'>\r\n        <meta name=\'viewport\' content=\'width=device-width, initial-scale=1.0\'>\r\n        <style>\r\n            body { font-family: \'Segoe UI\', Roboto, Helvetica, Arial, sans-serif; line-height: 1.6; color: #1e293b; margin: 0; padding: 0; background-color: #f0f4f8; }\r\n            .wrapper { width: 100%; table-layout: fixed; background-color: #f0f4f8; padding-bottom: 40px; }\r\n            .container { max-width: 600px; margin: 0 auto; background-color: #ffffff; border-radius: 16px; overflow: hidden; margin-top: 40px; box-shadow: 0 15px 35px rgba(0,0,0,0.1); border: 1px solid #e2e8f0; }\r\n            .header { background-color: #1a1a2e; padding: 40px 20px; text-align: center; border-bottom: 5px solid #c8a951; }\r\n            .header h1 { color: #ffffff; margin: 0; font-size: 22px; letter-spacing: 2px; text-transform: uppercase; font-weight: 700; }\r\n            .header p { color: #c8a951; margin: 5px 0 0; text-transform: uppercase; font-size: 11px; font-weight: 800; letter-spacing: 1.5px; }\r\n            .content { padding: 40px 35px; }\r\n            .greeting { font-size: 22px; color: #1a1a2e; margin-bottom: 20px; font-weight: 700; }\r\n            .status-line { color: #8b1a2b; font-weight: 700; font-size: 18px; margin-bottom: 20px; }\r\n            .details-box { background-color: #fffaf0; border-radius: 12px; padding: 30px; margin: 25px 0; border: 1px solid #fbd38d; }\r\n            .details-title { font-size: 16px; font-weight: 700; color: #1a1a2e; margin-bottom: 20px; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid #fbd38d; padding-bottom: 10px; }\r\n            .detail-item { margin-bottom: 15px; display: flex; align-items: baseline; }\r\n            .detail-label { font-weight: 700; color: #718096; width: 130px; font-size: 12px; text-transform: uppercase; }\r\n            .detail-value { font-weight: 600; color: #2d3748; flex: 1; font-size: 15px; }\r\n            .footer { padding: 30px; text-align: center; font-size: 12px; color: #94a3b8; background-color: #f8fafc; border-top: 1px solid #e2e8f0; }\r\n            .confirm-btn { display: inline-block; padding: 12px 24px; border-radius: 8px; font-weight: bold; text-decoration: none; color: #ffffff !important; transition: background-color 0.2s; }\r\n            .confirm-btn.yes { background-color: #10b981; }\r\n            .confirm-btn.no { background-color: #ef4444; }\r\n        </style>\r\n    </head>\r\n    <body>\r\n        <div class=\'wrapper\'>\r\n            <div class=\'container\'>\r\n                <div class=\'header\'>\r\n                    <h1>GEORGE STEUART</h1>\r\n                    <p>ESTABLISHED 1835</p>\r\n                </div>\r\n                <div class=\'content\'>\r\n                    <div class=\'greeting\'>Dear Nimal,</div>\r\n                    <p>We are pleased to inform you that after reviewing your application for the position of <strong>Senior Executive – Human Resources (Payroll & Talent Development)</strong> (Ref: ST/2026/26/001), you have been <span style=\'color: #c8a951; font-weight: 800;\'>SHORTLISTED</span> for the next stage of our selection process.</p>\r\n                    \r\n                    <div class=\'details-box\'>\r\n                        <div class=\'details-title\'>Interview Details</div>\r\n                        <div class=\'detail-item\'>\r\n                            <div class=\'detail-label\'>Type</div>\r\n                            <div class=\'detail-value\'>On-site</div>\r\n                        </div>\r\n                        <div class=\'detail-item\'>\r\n                            <div class=\'detail-label\'>Date</div>\r\n                            <div class=\'detail-value\'>2026-06-25</div>\r\n                        </div>\r\n                        <div class=\'detail-item\'>\r\n                            <div class=\'detail-label\'>Time</div>\r\n                            <div class=\'detail-value\'>10:00</div>\r\n                        </div>\r\n                        <div class=\'detail-item\'>\r\n                            <div class=\'detail-label\'>Location</div>\r\n                            <div class=\'detail-value\'>aafwfw</div>\r\n                        </div>\r\n                        \r\n                    </div>\r\n\r\n                    <p style=\'margin-top: 25px; font-weight: bold;\'>Please confirm your availability for this schedule by clicking one of the buttons below:</p>\r\n                    <div style=\'text-align: center; margin: 25px 0;\'>\r\n                        <a href=\'http://localhost:3000/confirm-interview?id=12&response=yes\' class=\'confirm-btn yes\' style=\'margin-right: 15px;\'>Yes, I am available</a>\r\n                        <a href=\'http://localhost:3000/confirm-interview?id=12&response=no\' class=\'confirm-btn no\'>No, I cannot attend</a>\r\n                    </div>\r\n\r\n                    <p>We look forward to discussing your potential contribution to George Steuart Group.</p>\r\n\r\n                    <p style=\'margin-top: 30px;\'>Best regards,<br>\r\n                    <strong style=\'color: #1a1a2e;\'>Talent Acquisition Team</strong><br>\r\n                    George Steuart Group</p>\r\n                </div>\r\n                <div class=\'footer\'>\r\n                    &copy; 2026 George Steuart Group. All Rights Reserved.<br>\r\n                    No. 439, Galle Road, Colombo 03, Sri Lanka.<br>\r\n                    <p style=\'font-size: 10px; margin-top: 10px;\'>This is an automated notification.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </body>\r\n    </html>', 'sent', '1', NULL, '2026-06-23 10:00:11', '2026-06-23 10:00:18');
