served.\r\n                </p>\r\n              </td>\r\n            </tr>\r\n\r\n          </table>\r\n        </td></tr>\r\n      </table>\r\n    </body>\r\n    </html>\r\n    ', 'sent', '1', NULL, '2026-06-25 08:59:31', '2026-06-25 08:59:44');
