b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Company</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'>George Steuart Solutions (Pvt) Ltd</div>\r\n      </td>\r\n    </tr>\r\n    \r\n    <tr>\r\n      <td style=\'padding:12px 0;border-bottom:1px solid #dcfce7;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Status</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'>\r\n    <span style=\'display:inline-block;background-color:#dcfce7;color:#166534;padding:5px 14px;border-radius:100px;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:1px;line-height:1.2;vertical-align:middle;\'>\r\n      <span style=\'width:6px;height:6px;border-radius:50%;background-color:#16a34a;display:inline-block;vertical-align:middle;margin-right:6px;margin-top:-2px;\'></span>\r\n      <span style=\'vertical-align:middle;\'>APPROVED &amp; LIVE</span>\r\n    </span>\r\n    </div>\r\n      </td>\r\n    </tr>\r\n    \r\n            </table>\r\n          </div>\r\n\r\n          <div style=\'text-align:center;margin-bottom:8px;\'>\r\n            \r\n    <table cellpadding=\'0\' cellspacing=\'0\' style=\'margin:0 auto;width:100%;max-width:280px;\'>\r\n      <tr>\r\n        <td align=\'center\' style=\'border-radius:10px;background:#16a34a;\'>\r\n          <a href=\'http://localhost:3000/admin/vacancies?highlight=64\' target=\'_blank\'\r\n             style=\'display:block;padding:14px 24px;font-size:14px;font-weight:700;color:#ffffff;text-decoration:none;border-radius:10px;letter-spacing:0.3px;text-align:center;\'>\r\n            &#128196;&nbsp; View Vacancy in Portal\r\n          </a>\r\n        </td>\r\n      </tr>\r\n    </table>\r\n    \r\n          </div>\r\n        \r\n              </td>\r\n            </tr>\r\n\r\n            <!-- FOOTER -->\r\n            <tr>\r\n              <td class=\'email-footer\' style=\'background:#f8fafc;border-top:1px solid #e2e8f0;border-radius:0 0 15px 15px;padding:20px 36px;text-align:center;\'>\r\n                <p style=\'margin:0;font-size:11px;color:#94a3b8;line-height:1.6;\'>\r\n                  This is an automated notification from the George Steuart Careers Portal.<br>\r\n                  Please do not reply directly to this email.\r\n                </p>\r\n                <p style=\'margin:8px 0 0;font-size:10px;color:#cbd5e1;\'>\r\n                  &copy; 2026 George Steuart &amp; Company Ltd. All rights reserved.\r\n                </p>\r\n              </td>\r\n            </tr>\r\n\r\n          </table>\r\n        </td></tr>\r\n      </table>\r\n    </body>\r\n    </html>\r\n    ', 'sent', '1', NULL, '2026-06-25 09:21:21', '2026-06-25 09:21:27');
