-bottom:1px solid #f1f5f9;\'>\r\n        <div style=\'font-size:10px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1.2px;margin-bottom:4px;\'>Company</div>\r\n        <div style=\'font-size:14px;color:#1e293b;font-weight:600;line-height:1.4;\'>George Steuart Solutions (Pvt) Ltd</div>\r\n      </td>\r\n    </tr>\r\n    \r\n            </table>\r\n          </div>\r\n\r\n          <!-- Note -->\r\n          <div style=\'background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:14px 18px;margin-bottom:28px;\'>\r\n            <p style=\'margin:0 0 4px;font-size:11px;font-weight:700;color:#c2410c;text-transform:uppercase;letter-spacing:0.5px;\'>&#9888;&nbsp; Action Required</p>\r\n            <p style=\'margin:0 0 8px;font-size:13px;color:#475569;\'>Please log in to the Careers Portal and review this requisition. You can approve it to make it live, or reject it with a reason.</p>\r\n          </div>\r\n\r\n          <!-- CTA Button -->\r\n          <div style=\'text-align:center;margin-bottom:8px;\'>\r\n            \r\n    <table cellpadding=\'0\' cellspacing=\'0\' style=\'margin:0 auto;width:100%;max-width:280px;\'>\r\n      <tr>\r\n        <td align=\'center\' style=\'border-radius:10px;background:#2a050b;\'>\r\n          <a href=\'http://localhost:3000/admin/approvals?highlight=67\' target=\'_blank\'\r\n             style=\'display:block;padding:14px 24px;font-size:14px;font-weight:700;color:#ffffff;text-decoration:none;border-radius:10px;letter-spacing:0.3px;text-align:center;\'>\r\n            &#9989;&nbsp; Review &amp; Give Final Approval\r\n          </a>\r\n        </td>\r\n      </tr>\r\n    </table>\r\n    \r\n          </div>\r\n        \r\n              </td>\r\n            </tr>\r\n\r\n            <!-- FOOTER -->\r\n            <tr>\r\n              <td class=\'email-footer\' style=\'background:#f8fafc;border-top:1px solid #e2e8f0;border-radius:0 0 15px 15px;padding:20px 36px;text-align:center;\'>\r\n                <p style=\'margin:0;font-size:11px;color:#94a3b8;line-height:1.6;\'>\r\n                  This is an automated notification from the George Steuart Careers Portal.<br>\r\n                  Please do not reply directly to this email.\r\n                </p>\r\n                <p style=\'margin:8px 0 0;font-size:10px;color:#cbd5e1;\'>\r\n                  &copy; 2026 George Steuart &amp; Company Ltd. All rights reserved.\r\n                </p>\r\n              </td>\r\n            </tr>\r\n\r\n          </table>\r\n        </td></tr>\r\n      </table>\r\n    </body>\r\n    </html>\r\n    ', 'sent', '1', NULL, '2026-06-26 16:00:48', '2026-06-26 16:00:56');
